graph TD
    A[package.json] --> B{Main Package Entry};
    B --> C[dist/index.js];
    A --> D{CLI Commands};
    D --> E[buddy];
    D --> F[code-buddy];
    A --> G{Plugin SDK Exports};
    G --> H[./plugin-sdk];
    G --> I[./plugin-sdk/core];
    G --> J[./plugin-sdk/llm];
    G --> K[...other plugin-sdk exports];
```
